    {
      "path": "src/modules/members/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const membersByProjectId = {};

async function addMember(projectId, data) {
  if (!membersByProjectId[projectId]) {
    membersByProjectId[projectId] = [];
  }
  const existingMember = membersByProjectId[projectId].find(m => m.userId === data.userId);
  if (existingMember) {
    throw new Error('Duplicate member');
  }
  const member = {
    id: randomUUID(),
    userId: data.userId,
    role: data.role,
  };
  membersByProjectId[projectId].push(member);
  return member;
}

async function listMembers(projectId) {
  return membersByProjectId[projectId] || [];
}

module.exports = {
  addMember,
  listMembers,
};"
